import React from 'react';
import { useUserStore } from '../stores/userStore';

interface User {
  id: string;
  name: string;
  email: string;
}

export const UserList: React.FC = () => {
  const { users, loading, error } = useUserStore();

  if (loading) return <div>Loading...</div>;
  if (error) return <div>Error: {error}</div>;

  // Line 42 - the crash site
  return (
    <ul>
      {users.map((user: User) => (
        <li key={user.id}>
          {user.name} ({user.email})
        </li>
      ))}
    </ul>
  );
};

import { create } from 'zustand';
import { fetchUsers } from '../api/users';

interface UserStore {
  users: User[] | null;
  loading: boolean;
  error: string | null;
  fetchUsers: () => Promise<void>;
}

export const useUserStore = create<UserStore>((set) => ({
  users: null,  // <-- initialized as null!
  loading: false,
  error: null,

  fetchUsers: async () => {
    set({ loading: true, error: null });
    try {
      const response = await fetchUsers();
      // Yesterday's change: API now returns { data: { users: [...] } }
      // Previously it returned { users: [...] }
      set({ users: response.data?.users ?? null, loading: false });
    } catch (err) {
      set({ error: (err as Error).message, loading: false });
    }
  },
}));

import { apiClient } from './client';

interface ApiResponse<T> {
  data: T;
  meta?: { total: number; page: number };
}

interface User {
  id: string;
  name: string;
  email: string;
}

export async function fetchUsers(): Promise<ApiResponse<User[]>> {
  const response = await apiClient.get<ApiResponse<User[]>>('/users');
  return response.data;
}

// NOTE: The API was migrated to a new envelope format.
// Old: { users: [...] }
// New: { data: { users: [...] } }
// But actually the new format is { data: [...] } NOT { data: { users: [...] } }
// The store is accessing response.data.users which is undefined!

